theme.css:
/* Rivian Supplier & Parts Onboarding — design tokens (mined from Supplier Onboarding.dc.html :root).
   Dark enterprise theme, near-black canvas, Rivian-yellow accent. This is the pixel source-of-truth
   and the ODC theme.StyleSheet payload. Load fonts via @font-face (ODC strips @import on publish). */

/* ── Real fonts via @font-face (fontsource CDN — stable, survives ODC publish) ── */
@font-face{font-family:'IBM Plex Sans';font-style:normal;font-weight:400;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/ibm-plex-sans@latest/latin-400-normal.woff2') format('woff2');}
@font-face{font-family:'IBM Plex Sans';font-style:normal;font-weight:500;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/ibm-plex-sans@latest/latin-500-normal.woff2') format('woff2');}
@font-face{font-family:'IBM Plex Sans';font-style:normal;font-weight:600;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/ibm-plex-sans@latest/latin-600-normal.woff2') format('woff2');}
@font-face{font-family:'Space Grotesk';font-style:normal;font-weight:500;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/space-grotesk@latest/latin-500-normal.woff2') format('woff2');}
@font-face{font-family:'Space Grotesk';font-style:normal;font-weight:600;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/space-grotesk@latest/latin-600-normal.woff2') format('woff2');}
@font-face{font-family:'Space Grotesk';font-style:normal;font-weight:700;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/space-grotesk@latest/latin-700-normal.woff2') format('woff2');}
@font-face{font-family:'JetBrains Mono';font-style:normal;font-weight:500;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/jetbrains-mono@latest/latin-500-normal.woff2') format('woff2');}
@font-face{font-family:'JetBrains Mono';font-style:normal;font-weight:600;font-display:swap;src:url('https://cdn.jsdelivr.net/fontsource/fonts/jetbrains-mono@latest/latin-600-normal.woff2') format('woff2');}

:root{
  /* surfaces */
  --bg:#0c0e0c; --panel:#131612; --panel-2:#191d17; --panel-3:#1f241d;
  --line:#2a2f27; --line-soft:#20241d;
  /* text tiers */
  --ink:#edefe8; --ink-2:#a3a99c; --ink-3:#6d7266; --ink-4:#4a4e44;
  /* brand accent + feedback */
  --yellow:#ffd329; --green:#7fce8f; --amber:#f0b657; --red:#ef7d6b; --blue:#79b0e6;
  /* typography */
  --font-body:'IBM Plex Sans',system-ui,sans-serif;
  --font-head:'Space Grotesk',sans-serif;
  --font-mono:'JetBrains Mono',monospace;
  /* spacing + radii */
  --sp-1:4px; --sp-2:8px; --sp-3:12px; --sp-4:16px; --sp-5:20px; --sp-6:28px;
  --r-1:3px; --r-2:5px; --r-3:10px; --sidebar-w:248px;
}

/* ── base ── */
body,.screen-container{background:var(--bg);color:var(--ink);font-family:var(--font-body);font-size:14px;line-height:1.5;}
h1,h2,h3,h4,h5,.kpi-value{font-family:var(--font-head);letter-spacing:-.01em;}
body{padding-left:var(--sidebar-w);}
.screen-container,[data-screen],.content{padding:var(--sp-6) 34px;max-width:1180px;box-sizing:border-box;}
h1,h2{font-size:22px;font-weight:600;margin:0 0 var(--sp-1);}
hr{border:none;border-top:1px solid var(--line);margin:var(--sp-5) 0;}

/* ── app-shell sidebar ── */
.app-sidebar{position:fixed;left:0;top:0;bottom:0;width:var(--sidebar-w);overflow-y:auto;z-index:20;background:#0d0f0c;border-right:1px solid var(--line);padding:18px 14px;box-sizing:border-box;}
.sidebar-brand{color:var(--yellow);font-family:var(--font-head);font-weight:700;font-size:20px;letter-spacing:.04em;}
.sidebar-brand small,.sidebar-sub{display:block;color:var(--ink-3);font-family:var(--font-mono);font-size:10px;letter-spacing:.12em;text-transform:uppercase;margin-top:var(--sp-1);}
.nav-section{color:var(--ink-3);font-family:var(--font-mono);font-weight:600;font-size:10px;letter-spacing:.14em;text-transform:uppercase;margin:18px 6px 6px;}
.nav-item{display:flex;align-items:center;gap:10px;padding:9px 10px;border-radius:var(--r-2);color:#c9cdc2;text-decoration:none;font-size:14px;border-left:3px solid transparent;}
.nav-item:hover{background:#161810;}
.nav-item.is-active{background:#1a1d13;border-left:3px solid var(--yellow);color:var(--ink);font-weight:600;}
.nav-tag{font-family:var(--font-mono);font-weight:600;font-size:10px;letter-spacing:.08em;background:var(--line-soft);color:var(--ink-2);padding:3px 5px;border-radius:var(--r-1);}
.nav-badge{margin-left:auto;background:var(--line-soft);color:var(--ink-2);border-radius:10px;padding:1px 8px;font-size:11px;}
.sidebar-user{display:flex;align-items:center;gap:10px;margin-top:20px;padding-top:14px;border-top:1px solid var(--line);}
.online-dot{width:8px;height:8px;border-radius:50%;background:var(--green);margin-left:auto;}

/* ── top bar ── */
.app-topbar{display:flex;align-items:center;gap:var(--sp-4);padding:14px 20px;border-bottom:1px solid var(--line);}
.breadcrumb{color:var(--ink-3);font-size:13px;} .breadcrumb b{color:var(--ink);}
.env-chip{font-family:var(--font-mono);font-size:11px;color:var(--green);border:1px solid var(--line);border-radius:var(--r-1);padding:3px 8px;}

/* ── status cells ── */
.chip,.tag,.badge{display:inline-block;padding:3px 8px;border-radius:var(--r-1);font-family:var(--font-mono);font-weight:600;font-size:11px;letter-spacing:.04em;text-transform:uppercase;}
.chip{background:var(--line-soft);color:var(--ink);}
.chip-approved,.chip-clear,.chip-qualified,.chip-activated,.badge-approved,.badge-clear{background:rgba(127,206,143,.15);color:var(--green);}
.chip-in-review,.chip-pending,.badge-in-review,.badge-pending{background:rgba(240,182,87,.15);color:var(--amber);}
.chip-overdue,.chip-rejected,.chip-blocked,.badge-overdue,.badge-breached{background:rgba(239,125,107,.15);color:var(--red);}
.chip-screening,.badge-screening{background:rgba(121,176,230,.15);color:var(--blue);}
.tag-t1,.tag-critical{background:rgba(255,211,41,.15);color:var(--yellow);}
.tag-t2,.tag-standard{background:var(--line-soft);color:var(--ink-2);}
.cell-id{font-family:var(--font-mono);font-weight:500;font-size:12px;color:var(--ink-2);}
.avatar{width:28px;height:28px;border-radius:50%;background:var(--line);color:var(--ink);display:inline-flex;align-items:center;justify-content:center;font-family:var(--font-head);font-weight:600;font-size:11px;}

/* ── KPI dashboard ── */
.kpi-row{display:flex;gap:var(--sp-4);}
.kpi-card{flex:1;background:var(--panel);border:1px solid var(--line);border-radius:var(--r-2);padding:var(--sp-4);}
.kpi-icon{color:var(--yellow);font-size:16px;margin-bottom:var(--sp-2);}
.kpi-value{font-weight:600;font-size:28px;color:var(--ink);}
.kpi-label{color:var(--ink-3);font-size:12px;text-transform:uppercase;letter-spacing:.08em;margin-top:2px;}
.kpi-trend{color:var(--green);font-size:12px;margin-top:6px;}

/* ── case-detail: stepper + reviews + timeline ── */
.stepper{display:flex;gap:var(--sp-2);flex-wrap:wrap;margin:var(--sp-2) 0 18px;}
.step{padding:var(--sp-2) var(--sp-3);border-radius:var(--r-2);border:1px solid var(--line);background:var(--panel);color:var(--ink-3);font-size:13px;}
.step.is-done{border-color:var(--green);color:var(--green);}
.step.is-active{border-color:var(--yellow);color:var(--ink);box-shadow:0 0 0 1px var(--yellow) inset;}
.step.is-pending{opacity:.55;}
.review-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:var(--sp-3);margin:var(--sp-2) 0 18px;}
.review-card{background:var(--panel);border:1px solid var(--line);border-radius:var(--r-2);padding:var(--sp-3);}
.review-card h5{margin:0 0 var(--sp-2);font-size:13px;color:var(--ink-2);}
.timeline{border-left:2px solid var(--line);padding-left:14px;margin-top:var(--sp-2);}
.timeline-item{margin-bottom:var(--sp-3);color:var(--ink-2);font-size:13px;}

/* ── tables + primary CTA ── */
table{border-collapse:collapse;width:100%;}
th{text-align:left;color:var(--ink-3);font-family:var(--font-mono);font-weight:600;font-size:11px;text-transform:uppercase;letter-spacing:.06em;padding:10px;border-bottom:1px solid var(--line);}
td{padding:12px 10px;border-bottom:1px solid var(--line-soft);color:#c9cdc2;font-size:14px;}
tr:hover td{background:#10120f;}
.btn-primary,.is-primary{background:var(--yellow);color:#161810;border-radius:var(--r-2);font-weight:600;}
